.darma-loader-uiverse-countdown-spin-dial {
  position: relative;
  width: 100px;
  height: 100px;
  border-radius: 50%;
  display: flex;
  justify-content: center;
  align-items: center;
  background: radial-gradient(circle, #03dac6, #6200ea);
  border: 8px solid transparent;
  border-top-color: #03dac6;
  border-bottom-color: #6200ea;
  animation: darma-loader-uiverse-countdown-spin-dial-spin 2s linear infinite;
}

.darma-loader-uiverse-countdown-spin-dial::before {
content: "1";
position: absolute;
font-size: 24px;
font-weight: bold;
color: white;
animation: darma-loader-uiverse-countdown-spin-dial-count 10s linear infinite;
}

